const setupView=document.querySelector('#setup-view'),authView=document.querySelector('#auth-view'),shell=document.querySelector('#app-shell'),content=document.querySelector('#content'),toast=document.querySelector('#toast');
const nav=[...document.querySelectorAll('nav a')],state={csrf:null,user:null,mode:null,movies:[],tv:[],query:'',filter:'all',view:'poster',sort:'title',enginesConfigured:false,dirty:false,sessionMessage:''};
const esc=(value)=>String(value??'').replace(/[&<>"']/g,(char)=>({'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;',"'":'&#39;'}[char]));
const pct=(value)=>Math.max(0,Math.min(100,Number(value)||0));
