  async function loadPolicy(){if(indexer)return;const host=document.querySelector('#failed-download-policy');try{const{result}=await api(`/api/manage/${domain.value}/downloadClientSettings`);host.className='panel';host.innerHTML=`<form id="failed-download-form"><div class="panel-heading"><div><h2>Failed download handling</h2><p class="muted">Choose whether the engine should block a failed release and automatically grab another result.</p></div><button class="primary" type="submit">Save policy</button></div><div class="form-grid"><label class="check"><input name="enableCompletedDownloadHandling" type="checkbox"${result.enableCompletedDownloadHandling?' checked':''}> Process completed downloads</label><label class="check"><input name="autoRedownloadFailed" type="checkbox"${result.autoRedownloadFailed?' checked':''}> Automatically replace failed automatic/manual grabs</label><label class="check"><input name="autoRedownloadFailedFromInteractiveSearch" type="checkbox"${result.autoRedownloadFailedFromInteractiveSearch?' checked':''}> Automatically replace failed interactive grabs</label></div></form>`;host.querySelector('form').addEventListener('submit',async event=>{event.preventDefault();const target=event.currentTarget,payload={...result,enableCompletedDownloadHandling:target.elements.enableCompletedDownloadHandling.checked,autoRedownloadFailed:target.elements.autoRedownloadFailed.checked,autoRedownloadFailedFromInteractiveSearch:target.elements.autoRedownloadFailedFromInteractiveSearch.checked};try{await api(`/api/manage/${domain.value}/downloadClientSettings`,{method:'PUT',body:JSON.stringify(payload)});notify('Failed-download policy saved.');await loadPolicy();}catch(error){notify(error.message,'error');}});}catch(error){host.className='panel error-state';host.innerHTML=`<p>${esc(error.message)}</p>`;}}
  function control(field,i){const value=field.value??'',secret=['password','apiKey'].includes(field.privacy)||field.type==='password';if(['checkbox','boolean'].includes(field.type))return`<label class="check provider-field"><input data-field="${i}" type="checkbox"${value?' checked':''}> ${esc(field.label||field.name)}${field.advanced?' (Advanced)':''}</label>`;if(field.type==='select'&&field.selectOptions?.length){const multi=Array.isArray(value),selected=multi?value.map(String):[String(value)];return`<label class="provider-field">${esc(field.label||field.name)}${field.advanced?' <small>Advanced</small>':''}<select data-field="${i}"${multi?' multiple':''}>${field.selectOptions.map(option=>`<option value="${esc(option.value)}"${selected.includes(String(option.value))?' selected':''}>${esc(option.name)}${option.hint?` ${esc(option.hint)}`:''}</option>`).join('')}</select>${field.helpText?`<small>${esc(field.helpText)}</small>`:''}</label>`;}return`<label class="provider-field">${esc(field.label||field.name)}${field.advanced?' <small>Advanced</small>':''}<input data-field="${i}" type="${secret?'password':field.type==='number'?'number':'text'}" value="${esc(value==='********'?'':value)}"${field.isFloat?' step="any"':''}>${field.helpText?`<small>${esc(field.helpText)}</small>`:''}</label>`;}
